// // This module implements a 8-bit register that captures the input data on the negative edge of the clock signal and updates the output only when the enable signal is low.
module Register8bit (
	input clk,
	input reset,
	input enable,
	input [7:0] d,
	output reg [7:0] q
);
    always @(posedge clk or posedge reset) begin
        if (reset)
            q <= 8'b00000000;
        else if (enable)
            q <= d;
    end
endmodule
